import { useState } from "react";

function App() {
  const [dream, setDream] = useState("");
  const [result, setResult] = useState("");

  const analyzeDream = () => {
    if (dream.trim() === "") {
      setResult("Please enter a dream first.");
    } else {
      setResult("This dream shows your thoughts and emotions.");
    }
  };

  return (
      <div style={{
        padding: "40px",
        fontFamily: "Arial",
        textAlign: "center"
      }}>
        <h1>Dream Analyzer 🌙</h1>

        <textarea
            placeholder="Enter your dream..."
            value={dream}
            onChange={(e) => setDream(e.target.value)}
            style={{
              width: "300px",
              height: "100px",
              padding: "10px"
            }}
        />

        <br /><br />

        <button onClick={analyzeDream}>
          Analyze Dream
        </button>

        <h3>Result:</h3>
        <p>{result}</p>
      </div>
  );
}

export default App;
